struct Json {
    using arr=std::vector<Json>; using obj=std::map<std::string,Json>;
    std::variant<std::nullptr_t,bool,double,std::string,arr,obj> v;
    Json():v(nullptr){} Json(double x):v(x){} Json(std::string s):v(std::move(s)){} Json(arr a):v(std::move(a)){} Json(obj o):v(std::move(o)){} Json(bool b):v(b){}
    bool isObj()const{return std::holds_alternative<obj>(v);} bool isArr()const{return std::holds_alternative<arr>(v);} bool isStr()const{return std::holds_alternative<std::string>(v);} bool isNum()const{return std::holds_alternative<double>(v);} bool isBool()const{return std::holds_alternative<bool>(v);} bool isNull()const{return std::holds_alternative<std::nullptr_t>(v);} 
    const obj& asObj()const{return std::get<obj>(v);} const arr& asArr()const{return std::get<arr>(v);} const std::string& asStr()const{return std::get<std::string>(v);} int asInt()const{return (int)std::get<double>(v);} double asNum()const{return std::get<double>(v);} bool asBool()const{return std::get<bool>(v);} 
    const Json& at(const std::string& k)const{auto& o=asObj(); auto it=o.find(k); if(it==o.end()) throw std::runtime_error("missing json key: "+k); return it->second;} bool has(const std::string& k)const{return isObj()&&asObj().count(k);} };
struct Parser{std::string s; size_t p=0; explicit Parser(std::string x):s(std::move(x)){} void ws(){while(p<s.size()&&std::isspace((unsigned char)s[p]))p++;} char peek(){ws(); return p<s.size()?s[p]:'\0';} char get(){ws(); if(p>=s.size()) throw std::runtime_error("unexpected eof"); return s[p++];}
 Json parse(){auto j=val(); ws(); if(p!=s.size()) throw std::runtime_error("trailing json"); return j;} Json val(){char c=peek(); if(c=='{')return objv(); if(c=='[')return arrv(); if(c=='\"')return Json(str()); if(c=='t'){lit("true");return Json(true);} if(c=='f'){lit("false");return Json(false);} if(c=='n'){lit("null");return Json();} return num();}
 void lit(const char* w){ws(); for(;*w;w++) if(p>=s.size()||s[p++]!=*w) throw std::runtime_error("bad literal");}
 std::string str(){if(get()!='\"')throw std::runtime_error("expected string"); std::string r; while(p<s.size()){char c=s[p++]; if(c=='\"')return r; if(c=='\\'){ if(p>=s.size())break; char e=s[p++]; if(e=='n')r+='\n'; else if(e=='t')r+='\t'; else if(e=='r')r+='\r'; else r+=e;} else r+=c;} throw std::runtime_error("unterminated string");}
 Json num(){ws(); size_t b=p; if(s[p]=='-')p++; while(p<s.size()&&isdigit((unsigned char)s[p]))p++; if(p<s.size()&&s[p]=='.'){p++; while(p<s.size()&&isdigit((unsigned char)s[p]))p++;} return Json(std::stod(s.substr(b,p-b)));}
 Json arrv(){get(); Json::arr a; if(peek()==']'){p++;return Json(a);} while(true){a.push_back(val()); char c=get(); if(c==']')break; if(c!=',')throw std::runtime_error("expected , or ]");} return Json(a);} Json objv(){get(); Json::obj o; if(peek()=='}'){p++;return Json(o);} while(true){std::string k=str(); if(get()!=':')throw std::runtime_error("expected :"); o[k]=val(); char c=get(); if(c=='}')break; if(c!=',')throw std::runtime_error("expected , or }");} return Json(o);} };

struct CodeBlock; struct Function{std::shared_ptr<CodeBlock> cb;}; struct Value;
using List=std::shared_ptr<std::vector<Value>>; using Dict=std::shared_ptr<std::map<std::string,Value>>;
struct Value{std::variant<std::nullptr_t,bool,long long,double,std::string,Function,List,Dict> v; Value():v(nullptr){} Value(bool x):v(x){} Value(long long x):v(x){} Value(double x):v(x){} Value(std::string x):v(std::move(x)){} Value(Function f):v(f){} Value(List l):v(l){} Value(Dict d):v(d){} };
static std::string valstr(const Value& x){struct V{std::string operator()(std::nullptr_t)const{return"null";} std::string operator()(bool b)const{return b?"true":"false";} std::string operator()(long long i)const{return"int("+std::to_string(i)+")";} std::string operator()(double d)const{std::ostringstream o;o<<"double("<<d<<")";return o.str();} std::string operator()(const std::string&s)const{return"string(\""+s+"\")";} std::string operator()(const Function&f)const{return f.cb?std::string("function") : std::string("function(null)");} std::string operator()(const List&l)const{std::string r="["; for(size_t i=0;i<l->size();++i){if(i)r+=", "; r+=valstr((*l)[i]);} return r+"]";} std::string operator()(const Dict&d)const{std::string r="{"; bool first=true; for(auto&kv:*d){if(!first)r+=", "; first=false; r+=kv.first+":"+valstr(kv.second);} return r+"}";}}; return std::visit(V{},x.v);} 
static bool truthy(const Value&v){ if(std::holds_alternative<std::nullptr_t>(v.v))return false; if(auto b=std::get_if<bool>(&v.v))return *b; if(auto i=std::get_if<long long>(&v.v))return *i!=0; if(auto d=std::get_if<double>(&v.v))return *d!=0; if(auto s=std::get_if<std::string>(&v.v))return !s->empty(); return true; }
struct Instruction{int opcode=0; std::string opname; int oparg=0; int line=-1; int resolvedTarget=-1;};
struct ExceptionTableItem{int startIp=0,endIp=0,handlerIp=0; std::string type;};
struct CodeBlock{std::string type="normal", cbname="root"; std::vector<Value> constants; std::vector<std::string> names; std::vector<std::shared_ptr<CodeBlock>> blocks; std::vector<Instruction> instructions; std::vector<ExceptionTableItem> exceptiontable; std::vector<int> instlnums; int baseline=0,currline=-1; std::vector<std::string> argnames,flags,inherits,generics;};
struct OpcodeSpec{std::string name; int opcode=0,numpop=0,numpush=0; std::string kind="None";};
struct Program{int version=1; std::string entry="main"; std::shared_ptr<CodeBlock> root; std::unordered_map<std::string,int> opcodeNameToId; std::unordered_map<int,OpcodeSpec> specs;};
static std::vector<std::string> coreOps={"OPCODE_ILL","ALLOC_CLASS_TYPE","BINARY_OP","BUILD_DICT","BUILD_LIST","CALL","COMPARE_OP","CREATE_INSTANCE","DECLARE_IMPORT","DECLARE_PACKAGE","DEFINE_CLASS","DEFINE_FUN","DEFINE_FUNCTION","DEFINE_MODULE","DEFINE_ANNOTATION","DEFINE_FLAW","RHINO_ECHO","FOR_ITER","GARBAGE_COLLECT","GET_ITER","JUMP_BACKWARD","JUMP_FORWARD","LOAD_ARG","LOAD_ATTR","LOAD_BUILTIN_FUNC","LOAD_BUILTIN_FUNC_BY_ID","LOAD_CONST","LOAD_CONST_VAR","LOAD_ENV_VAR","LOAD_FUNCTION","LOAD_FUNC_VARG","LOAD_GLOBAL","LOAD_IMM8","LOAD_LAMBDA","LOAD_MODULE","LOAD_NAME","LOAD_SCRIPT","LOAD_SENSE_PARSER","LOAD_SUBSCR","LOAD_FLAW","MAKE_FUNCTION","PARSE_MODULE_ATTRS","POP_JUMP_IF_FALSE","POP_JUMP_IF_TRUE","POP_TOP","RETURN_VALUE","STORE_ATTR","STORE_CONST_VAR","STORE_ENV_VAR","STORE_GLOBAL","STORE_GLOBAL_CONST","STORE_NAME","STORE_NAME_CONST","STORE_SCRIPT","STORE_SCRIPT_CONST","STORE_SUBSCR","TO_BOOL","TO_STRING","THROW","CATCH","REPLACE_FUNCTION","JUMP_IF_FALSE_OR_POP","JUMP_IF_TRUE_OR_POP","UNARY_OP","SLICE","UNLET_ATTR","UNLET_GLOBAL","UNLET_NAME","UNLET_SCRIPT","UNLET_SUBSCR","UNPACK_LIST","UNPACK_DICT","INSTANCE_OF","INSTANCE_NOT","DEFER_CALL","LOAD_NONE","LOAD_NAMED_PARAM","BIND_NAMED_PARAM","LOAD_NOTE","TYPE_CAST","LOAD_INHERIT","STORE_INHERIT","SET_FQN","UNSET_FQN","TENNIS_CALL","EXEC_NETABLOCK","SOURCE_MODULE","SCRIPT_FINISH","ADD_MEMORY_CLASS","GET_CALLER_MODULE","SLEEP","EXTENDED_ARG","LOAD_SCRIPT_ID","LOAD_GADGET_FUNC","GET_PATH_BY_FQN","EXECUTE_SOURCE","LOAD_VAR","STORE_VAR","LOAD_GVAR","STORE_GVAR","LOAD_TVAR","STORE_TVAR","LOAD_BVAR","STORE_BVAR","YIELD_VALUE","POP_LOAD","POP_UNPACK","OPCODE_NUM"};
static std::string kindFor(const std::string&op){ if(op.find("CONST")!=std::string::npos||op=="LOAD_IMM8")return"ConstIndex"; if(op.find("NAME")!=std::string::npos||op.find("GLOBAL")!=std::string::npos||op.find("VAR")!=std::string::npos||op.find("ATTR")!=std::string::npos||op.find("SUBSCR")!=std::string::npos||op=="LOAD_BUILTIN_FUNC")return"NameIndex"; if(op.find("JUMP")!=std::string::npos)return"JumpTarget"; if(op.find("DEFINE")!=std::string::npos)return"BlockIndex"; if(op=="CALL")return"ArgCount"; if(op=="BINARY_OP")return"BinaryOp"; if(op=="UNARY_OP")return"UnaryOp"; if(op=="COMPARE_OP")return"CompareOp"; return"None"; }
static void initOps(Program&p){int id=0; for(auto&n:coreOps){p.opcodeNameToId[n]=id; p.specs[id]={n,id,0,0,kindFor(n)}; id++;}}
static Value loadValue(const Json&j){ if(j.isObj()&&j.has("type")){auto t=j.at("type").asStr(); if(t=="int")return Value((long long)j.at("value").asInt()); if(t=="double")return Value(j.at("value").asNum()); if(t=="string")return Value(j.at("value").asStr()); if(t=="bool")return Value(j.at("value").asBool()); if(t=="null")return Value();} if(j.isNum())return Value((long long)j.asInt()); if(j.isStr())return Value(j.asStr()); if(j.isBool())return Value(j.asBool()); return Value();}
static std::shared_ptr<CodeBlock> loadBlock(const Json&j, Program&p){auto cb=std::make_shared<CodeBlock>(); if(j.has("type"))cb->type=j.at("type").asStr(); if(j.has("cbname"))cb->cbname=j.at("cbname").asStr(); if(j.has("constants"))for(auto&x:j.at("constants").asArr())cb->constants.push_back(loadValue(x)); if(j.has("names"))for(auto&x:j.at("names").asArr())cb->names.push_back(x.asStr()); if(j.has("argnames"))for(auto&x:j.at("argnames").asArr())cb->argnames.push_back(x.asStr()); if(j.has("blocks"))for(auto&x:j.at("blocks").asArr())cb->blocks.push_back(loadBlock(x,p)); if(j.has("instructions"))for(auto&x:j.at("instructions").asArr()){Instruction in; if(x.has("op")){in.opname=x.at("op").asStr(); in.opcode=p.opcodeNameToId.count(in.opname)?p.opcodeNameToId[in.opname]:-1;} else {in.opcode=x.at("opcode").asInt(); in.opname=p.specs.count(in.opcode)?p.specs[in.opcode].name:"OPCODE_ILL";} if(x.has("arg"))in.oparg=x.at("arg").asInt(); if(x.has("target"))in.resolvedTarget=x.at("target").asInt(); if(x.has("line"))in.line=x.at("line").asInt(); cb->instructions.push_back(in);} if(j.has("exceptiontable")) for(auto&x:j.at("exceptiontable").asArr()){ExceptionTableItem e; if(x.has("startIp"))e.startIp=x.at("startIp").asInt(); if(x.has("endIp"))e.endIp=x.at("endIp").asInt(); if(x.has("handlerIp"))e.handlerIp=x.at("handlerIp").asInt(); if(x.has("type"))e.type=x.at("type").asStr(); cb->exceptiontable.push_back(e);} return cb;}
static Program loadProgram(const std::string&path){std::ifstream f(path); if(!f)throw std::runtime_error("cannot open "+path); std::stringstream ss; ss<<f.rdbuf(); Program p; initOps(p); Json j=Parser(ss.str()).parse(); if(j.has("version"))p.version=j.at("version").asInt(); if(j.has("entry"))p.entry=j.at("entry").asStr(); p.root=loadBlock(j.at("root"),p); return p;}
struct Frame{std::shared_ptr<CodeBlock> codeblock; int ip=0; std::vector<Value> stack,args; std::unordered_map<std::string,Value> locals; std::string frameName;};
struct VM{Program program; std::vector<Frame> frames; std::unordered_map<std::string,Value> globals; bool trace=false,dumpTables=false; Value ret; explicit VM(Program p):program(std::move(p)){} Frame& fr(){return frames.back();} Value pop(){auto& s=fr().stack; if(s.empty())throw err("stack underflow"); Value v=s.back(); s.pop_back(); return v;} void push(Value v){fr().stack.push_back(std::move(v));}
 std::string stackstr(const std::vector<Value>&s){std::string r="["; for(size_t i=0;i<s.size();++i){if(i)r+=", "; r+=valstr(s[i]);} return r+"]";} std::string name(int i){auto cb=fr().codeblock; if(i<0||i>=(int)cb->names.size())throw err("name index out of range"); return cb->names[i];} std::runtime_error err(const std::string&r){std::ostringstream o; if(!frames.empty()){auto&f=fr(); o<<"RuntimeError: frame: "<<f.frameName<<" ip: "<<f.ip<<" reason: "<<r<<" stack: "<<stackstr(f.stack);} else o<<"RuntimeError: "<<r; return std::runtime_error(o.str());}
 Value resolve(const std::string&n){auto&f=fr(); if(f.locals.count(n))return f.locals[n]; if(globals.count(n))return globals[n]; throw err("NameError: name not found: "+n);} std::string explain(const Instruction&i){auto cb=fr().codeblock; std::ostringstream o; std::string k=program.specs.count(i.opcode)?program.specs[i.opcode].kind:kindFor(i.opname); o<<"oparg kind: "<<k; if(k=="ConstIndex"&&i.oparg<(int)cb->constants.size())o<<" lookup: constants["<<i.oparg<<"] result: "<<valstr(cb->constants[i.oparg]); else if(k=="NameIndex"&&i.oparg<(int)cb->names.size())o<<" lookup: names["<<i.oparg<<"] result: \""<<cb->names[i.oparg]<<"\""; else if(k=="BlockIndex"&&i.oparg<(int)cb->blocks.size())o<<" lookup: blocks["<<i.oparg<<"] result: "<<cb->blocks[i.oparg]->cbname; else if(k=="BinaryOp")o<<" ; "<<binName(i.oparg); else if(k=="CompareOp")o<<" ; "<<cmpName(i.oparg); else if(k=="ArgCount")o<<" = "<<i.oparg; return o.str();}
 static std::string binName(int a){static std::vector<std::string> n={"NB_UNKNOWN","NB_ADD","NB_SUBTRACT","NB_MULTIPLY","NB_DEVIDE","NB_MOD","NB_AND2","NB_OR2"}; return a>=0&&a<(int)n.size()?n[a]:"NB_UNKNOWN";} static std::string cmpName(int a){static std::vector<std::string> n={"CMP_LT","CMP_LE","CMP_EQ","CMP_NE","CMP_GT","CMP_GE","CMP_IS","CMP_ISNOT"}; return a>=0&&a<(int)n.size()?n[a]:"CMP_UNKNOWN";}
 Value binary(int op,Value l,Value r){auto li=std::get_if<long long>(&l.v), ri=std::get_if<long long>(&r.v); if(op==1){ if(auto ls=std::get_if<std::string>(&l.v))return Value(*ls+ (std::holds_alternative<std::string>(r.v)?std::get<std::string>(r.v):valstr(r))); if(auto rs=std::get_if<std::string>(&r.v))return Value(valstr(l)+*rs); if(li&&ri)return Value(*li+*ri);} if(li&&ri){if(op==2)return Value(*li-*ri); if(op==3)return Value(*li**ri); if(op==4)return Value(*li/ *ri); if(op==5)return Value(*li%*ri); if(op==6)return Value(*li&&*ri); if(op==7)return Value(*li||*ri);} throw err("unsupported operands for "+binName(op));}
 Value compare(int op,Value l,Value r){auto li=std::get_if<long long>(&l.v), ri=std::get_if<long long>(&r.v); if(li&&ri){if(op==0)return Value(*li<*ri); if(op==1)return Value(*li<=*ri); if(op==2)return Value(*li==*ri); if(op==3)return Value(*li!=*ri); if(op==4)return Value(*li>*ri); if(op==5)return Value(*li>=*ri);} if(op==2)return Value(valstr(l)==valstr(r)); if(op==3)return Value(valstr(l)!=valstr(r)); throw err("unsupported compare "+cmpName(op));}
 void call(int argc){std::vector<Value> args(argc); for(int i=argc-1;i>=0;--i)args[i]=pop(); Value fn=pop(); if(auto f=std::get_if<Function>(&fn.v)){Frame nf; nf.codeblock=f->cb; nf.frameName=f->cb->cbname; nf.args=args; for(size_t i=0;i<args.size()&&i<f->cb->argnames.size();++i)nf.locals[f->cb->argnames[i]]=args[i]; frames.push_back(nf); return;} throw err("CALL target is not function");}
 void run(){Frame root; root.codeblock=program.root; root.frameName=program.root->cbname; frames.push_back(root); while(!frames.empty()){auto&f=fr(); if(f.ip<0||f.ip>=(int)f.codeblock->instructions.size()){frames.pop_back(); continue;} Instruction in=f.codeblock->instructions[f.ip]; auto before=f.stack; int oldip=f.ip++; std::string oldFrame=f.frameName; std::string exp=explain(in); try{exec(in);}catch(const std::runtime_error&e){throw;} if(trace){std::cout<<"[frame="<<oldFrame<<" ip="<<oldip<<"] "<<in.opname<<" "<<in.oparg<<" ; "<<exp<<" before stack: "<<stackstr(before)<<" after stack: "<<(frames.empty()?"[]":stackstr(fr().stack))<<"\n";}}}
 void exec(const Instruction&i){auto cb=fr().codeblock; if(i.opname=="LOAD_CONST")push(cb->constants.at(i.oparg)); else if(i.opname=="LOAD_IMM8")push(Value((long long)i.oparg)); else if(i.opname=="LOAD_NONE")push(Value()); else if(i.opname=="LOAD_NAME"||i.opname=="LOAD_VAR")push(resolve(name(i.oparg))); else if(i.opname=="STORE_NAME"||i.opname=="STORE_VAR")fr().locals[name(i.oparg)]=pop(); else if(i.opname=="LOAD_GLOBAL"||i.opname=="LOAD_GVAR")push(globals[name(i.oparg)]); else if(i.opname=="STORE_GLOBAL"||i.opname=="STORE_GVAR")globals[name(i.oparg)]=pop(); else if(i.opname=="POP_TOP")pop(); else if(i.opname=="RHINO_ECHO"){Value v=pop(); std::cout<<plain(v)<<"\n";} else if(i.opname=="BINARY_OP"){auto r=pop(),l=pop(); push(binary(i.oparg,l,r));} else if(i.opname=="COMPARE_OP"){auto r=pop(),l=pop(); push(compare(i.oparg,l,r));} else if(i.opname=="UNARY_OP"){auto v=pop(); if(i.oparg==1)push(v); else if(i.oparg==2){auto x=std::get_if<long long>(&v.v); if(!x)throw err("bad unary minus"); push(Value(-*x));} else if(i.oparg==4)push(Value(!truthy(v))); else throw err("unsupported unary op");} else if(i.opname=="TO_BOOL")push(Value(truthy(pop()))); else if(i.opname=="DEFINE_FUN"||i.opname=="DEFINE_FUNCTION"||i.opname=="DEFINE_GFUN"||i.opname=="DEFINE_TFUN")push(Value(Function{cb->blocks.at(i.oparg)})); else if(i.opname=="CALL")call(i.oparg); else if(i.opname=="RETURN_VALUE"){Value rv=fr().stack.empty()?Value():pop(); frames.pop_back(); if(!frames.empty())frames.back().stack.push_back(rv); else ret=rv;} else if(i.opname=="JUMP_FORWARD")fr().ip=(i.resolvedTarget>=0?i.resolvedTarget:fr().ip+i.oparg); else if(i.opname=="JUMP_BACKWARD")fr().ip=(i.resolvedTarget>=0?i.resolvedTarget:fr().ip-i.oparg); else if(i.opname=="POP_JUMP_IF_FALSE"){auto v=pop(); if(!truthy(v))fr().ip=(i.resolvedTarget>=0?i.resolvedTarget:i.oparg);} else if(i.opname=="POP_JUMP_IF_TRUE"){auto v=pop(); if(truthy(v))fr().ip=(i.resolvedTarget>=0?i.resolvedTarget:i.oparg);} else if(i.opname=="JUMP_IF_FALSE_OR_POP"){auto v=fr().stack.back(); if(!truthy(v))fr().ip=(i.resolvedTarget>=0?i.resolvedTarget:i.oparg); else pop();} else if(i.opname=="JUMP_IF_TRUE_OR_POP"){auto v=fr().stack.back(); if(truthy(v))fr().ip=(i.resolvedTarget>=0?i.resolvedTarget:i.oparg); else pop();} else if(i.opname=="BUILD_LIST"){auto l=std::make_shared<std::vector<Value>>(); std::vector<Value> tmp; for(int k=0;k<i.oparg;k++)tmp.push_back(pop()); for(auto it=tmp.rbegin();it!=tmp.rend();++it)l->push_back(*it); push(Value(l));} else if(i.opname=="BUILD_DICT"){auto d=std::make_shared<std::map<std::string,Value>>(); for(int k=0;k<i.oparg;k++){auto val=pop(); auto key=pop(); (*d)[plain(key)]=val;} push(Value(d));} else if(i.opname=="LOAD_SUBSCR"){auto idx=pop(), c=pop(); if(auto l=std::get_if<List>(&c.v)){auto n=std::get<long long>(idx.v); push((*(*l))[n]);} else if(auto d=std::get_if<Dict>(&c.v))push((*(*d))[plain(idx)]); else throw err("not subscriptable");} else if(i.opname=="STORE_SUBSCR"){auto val=pop(),idx=pop(),c=pop(); if(auto l=std::get_if<List>(&c.v)){auto n=std::get<long long>(idx.v); (*(*l))[n]=val;} else if(auto d=std::get_if<Dict>(&c.v))(*(*d))[plain(idx)]=val; else throw err("not subscriptable");} else if(i.opname=="LOAD_ARG")push(fr().args.at(i.oparg)); else throw err("opcode not implemented: "+i.opname);}
 static std::string plain(const Value&v){ if(auto i=std::get_if<long long>(&v.v))return std::to_string(*i); if(auto d=std::get_if<double>(&v.v)){std::ostringstream o;o<<*d;return o.str();} if(auto s=std::get_if<std::string>(&v.v))return *s; if(auto b=std::get_if<bool>(&v.v))return *b?"true":"false"; return valstr(v);} };
static void dumpBlock(const CodeBlock&cb, VM&vm){
    (void)vm;
    std::cout<<"=== CodeBlock: "<<cb.cbname<<" type="<<cb.type<<" ===\nconstants:";
    for(size_t i=0;i<cb.constants.size();++i)std::cout<<" ["<<i<<"] "<<valstr(cb.constants[i]);
    std::cout<<"\nnames:";
    for(size_t i=0;i<cb.names.size();++i)std::cout<<" ["<<i<<"] "<<cb.names[i];
    std::cout<<"\nblocks:"<<(cb.blocks.empty()?" empty":"");
    for(size_t i=0;i<cb.blocks.size();++i)std::cout<<" ["<<i<<"] "<<cb.blocks[i]->cbname;
    std::cout<<"\ninstructions:";
    for(size_t i=0;i<cb.instructions.size();++i){auto&in=cb.instructions[i]; std::cout<<" "<<std::setw(4)<<std::setfill('0')<<i<<std::setfill(' ')<<" "<<in.opname<<" "<<in.oparg; if(in.resolvedTarget>=0)std::cout<<" target="<<in.resolvedTarget;}
    std::cout<<"\nexceptiontable:"<<(cb.exceptiontable.empty()?" []":" ...")<<"\n";
    for(auto&b:cb.blocks)dumpBlock(*b,vm);
}
int main(int argc,char**argv){try{ if(argc<3||std::string(argv[1])!="run"){std::cerr<<"usage: rhino_lab run metadata.json [--trace] [--dump-tables] [--entry name]\n"; return 2;} Program p=loadProgram(argv[2]); VM vm(p); for(int i=3;i<argc;i++){std::string a=argv[i]; if(a=="--trace")vm.trace=true; else if(a=="--dump-tables")vm.dumpTables=true; else if(a=="--entry"&&i+1<argc)vm.program.entry=argv[++i];} if(vm.dumpTables)dumpBlock(*vm.program.root,vm); vm.run(); return 0;}catch(const std::exception&e){std::cerr<<e.what()<<"\n"; return 1;}}
